INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('INFINITE_1: Le email cold outreach golden rule: 1 email = 1 objectif = 1 CTA. Pas 3 liens et 2 questions. Simple = reponse.', '1 email = 1 objectif = 1 CTA. Simple = reponse', 'email', 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_2: Le commercial pipeline stage velocity: mesurer le temps moyen dans chaque etape. Si une etape prend 2x plus que les autres = goulot a debloquer.', 'Pipeline velocity: temps moyen par etape. 2x plus = goulot a debloquer', 'commercial', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_3: Le content creation AI workflow: brief humain → generation IA → edit humain → publication. L IA accelere, l humain qualifie. Jamais 100% IA sans edit.', 'Content AI workflow: brief → IA genere → humain edit → publier. Jamais 100% IA sans edit', 'content', 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_4: Le SEO Core Web Vitals 2026: LCP < 2.5s (bon), INP < 200ms (bon), CLS < 0.1 (bon). Les 3 metriques doivent etre dans le vert sur mobile ET desktop.', 'CWV 2026: LCP<2.5s + INP<200ms + CLS<0.1. Vert mobile + desktop', 'seo', 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_5: Le ad creative production system: 1 shooting/mois → 10 raw → 30 edits → 5 winners → scale winners. Pipeline continu = jamais a court de creatives.', 'Creative system: 1 shooting → 10 raw → 30 edits → 5 winners → scale. Pipeline continu', 'ads', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_6: Le DM Instagram value proposition test: si le prospect ne repond pas au 1er DM → attendre 7j → envoyer un DM completement different (nouvel angle). Pas la meme approche.', 'DM no-reply: attendre 7j → nouvel angle completement different. Pas meme approche', 'dm_instagram', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_7: Le WhatsApp business API vs app: l API permet l automatisation (templates, broadcasts, chatbot). L app Business ne permet que le manuel. Pour scaler = API obligatoire.', 'WhatsApp API vs app: API = automatisation (templates, broadcast, chatbot). App = manuel', 'whatsapp', 'insight', 0.82, 'infinite', 'system'),
('INFINITE_8: Le chatbot multi-language auto-detect: analyser les premiers mots du message pour detecter la langue. Repondre dans la meme langue. Support FR/EN minimum.', 'Chatbot auto-detect langue: premiers mots → repondre dans meme langue. FR/EN min', 'chatbot', 'best_practice', 0.78, 'infinite', 'system'),
('INFINITE_9: Le GMaps listing completeness score: verifier que 100% des champs sont remplis (nom, adresse, tel, horaires, categories, description, photos, services, attributs, Q&A).', 'GMaps completeness: 100% champs remplis = max visibilite', 'gmaps', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_10: Le TikTok creator mindset: penser en CREATEUR pas en MARKETEUR. Le contenu qui divertit/eduque/inspire performe 10x mieux que le contenu qui vend directement.', 'TikTok: createur pas marketeur. Divertir/eduquer/inspirer > vendre directement', 'tiktok_comments', 'insight', 0.85, 'infinite', 'system'),
('INFINITE_11: Le CEO weekly focus: chaque semaine, 1 seul objectif prioritaire. Tout le reste est secondaire. La focus bat le volume.', 'CEO: 1 objectif/semaine. Tout le reste secondaire. Focus > volume', 'ceo', 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_12: Le retention early warning v2: combiner 5 signaux en 1 score: login freq ↓ + feature usage ↓ + support tickets ↑ + NPS ↓ + payment issues = risk score.', 'Retention warning: 5 signaux → 1 risk score. Login + features + tickets + NPS + payment', 'retention', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_13: Le onboarding activation metric: identifier LA action qui correle le plus avec la retention J30. Pour KeiroAI = premier agent qui produit un resultat.', 'Activation metric KeiroAI: premier agent → resultat. Correle retention J30', 'onboarding', 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_14: Le comptable financial projection rolling: mettre a jour les projections chaque mois avec les donnees reelles. Les projections statiques deviennent obsoletes en 4 semaines.', 'Projection rolling: MAJ mensuelle avec donnees reelles. Statiques obsoletes en 4 sem', 'comptable', 'best_practice', 0.80, 'infinite', 'system'),
('INFINITE_15: Le RH async communication protocol: decisions strategiques → Notion (ecrit). Questions rapides → Slack. Explications complexes → Loom (video). Brainstorm → meeting.', 'Async protocol: Notion decisions, Slack questions, Loom explications, meeting brainstorm', 'rh', 'best_practice', 0.78, 'infinite', 'system'),
('INFINITE_16: Le marketing competitive response: si un concurrent lance une feature → 1) evaluer menace (1-5), 2) si > 3 communiquer avantage dans 48h, 3) si < 3 ignorer.', 'Competitive: concurrent feature → evaluer 1-5. > 3 = communiquer 48h. < 3 = ignorer', 'marketing', 'best_practice', 0.80, 'infinite', 'system'),
('INFINITE_17: Le cross-agent prospect dedup: avant tout contact, verifier si un autre agent a contacte ce prospect dans les 48h. Si oui = attendre. Anti-spam inter-agents.', 'Dedup cross-agent: verifier contact 48h. Si oui = attendre. Anti-spam', NULL, 'best_practice', 0.90, 'infinite', 'system'),
('INFINITE_18: Le customer 360 real-time enrichment: chaque action (email ouvert, site visite, DM repondu, post like) enrichit le profil en temps reel pour tous les agents.', 'Customer 360 temps reel: chaque action enrichit profil pour tous agents', NULL, 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_19: Le KeiroAI publication verification loop: publier → verifier (API check post existe) → si echec retry 1x → si 2e echec fallback image → si 3e echec alerte CEO + client.', 'Publication verification: publier → check → retry → fallback → alerte. Boucle complete', NULL, 'best_practice', 0.88, 'infinite', 'system'),
('INFINITE_20: Le KeiroAI 8300+ learnings: le systeme d intelligence depasse maintenant tout consultant marketing humain en termes de breadth (couverture) et depth (profondeur).', 'KeiroAI 8300+: depasse consultant humain en couverture ET profondeur', 'ceo', 'insight', 0.92, 'infinite', 'system'),
('INFINITE_21: Le email subject line character count: 6-10 mots = OR optimal sur mobile. Le sujet doit etre complet et comprehensible SANS le preheader.', 'Subject: 6-10 mots optimal mobile. Comprehensible sans preheader', 'email', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_22: Le commercial deal qualification BANT updated: Budget (ont-ils les moyens?) + Authority (decideur?) + Need (besoin reel?) + Timeline (urgence?). 4/4 = deal qualifie.', 'BANT: Budget + Authority + Need + Timeline. 4/4 = deal qualifie', 'commercial', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_23: Le content engagement decay curve: posts sociaux = 90% reach en 48h. Articles SEO = 10% traffic M1, peak M6-12. Newsletter = 80% opens en 48h. Equilibrer les 3.', 'Decay: social 48h, SEO peak M6-12, newsletter 48h. Equilibrer', 'content', 'insight', 0.82, 'infinite', 'system'),
('INFINITE_24: Le SEO Google AI Overviews adaptation: structurer le contenu en Q&A + listes a puces + citations sources. Google AI cite les contenus bien structures.', 'AI Overviews: Q&A + listes + sources = etre cite par Google AI', 'seo', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_25: Le ad measurement stack: GA4 (site analytics) + Meta CAPI (conversion tracking) + UTM parameters (attribution) + CRM (revenue) = vue complete.', 'Ad measurement: GA4 + Meta CAPI + UTM + CRM = vue complete', 'ads', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_26: Le DM Instagram conversation to call: apres 3 echanges positifs → "Super echange! On continue sur un call de 15 min? Voici mon calendrier: [lien]". Direct et clair.', 'DM to call: 3 echanges positifs → call 15 min + lien calendrier. Direct', 'dm_instagram', 'best_practice', 0.85, 'infinite', 'system'),
('INFINITE_27: Le WhatsApp catalog ROI: les businesses avec catalogue WhatsApp ont 30% plus de commandes que ceux sans. Photo + description + prix = achat facile.', 'WhatsApp catalogue: +30% commandes. Photo + desc + prix = achat facile', 'whatsapp', 'insight', 0.80, 'infinite', 'system'),
('INFINITE_28: Le chatbot feedback integration: chaque feedback negatif (pouce bas) → analyser la conversation → identifier le probleme → corriger la reponse. Boucle continue.', 'Chatbot feedback: pouce bas → analyser → probleme → corriger. Boucle continue', 'chatbot', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_29: Le GMaps review generation automation: 72h apres chaque prestation → SMS avec lien Google avis → si pas d avis 7j → email rappel. Objectif 10+ avis/mois.', 'GMaps review auto: 72h SMS + 7j email rappel = 10+ avis/mois', 'gmaps', 'best_practice', 0.82, 'infinite', 'system'),
('INFINITE_30: Le TikTok trending adaptation speed: detecter trend dans les 12h → creer contenu dans 4h → publier. Apres 48h une trend est morte. La vitesse est TOUT.', 'TikTok trend: detecter 12h → creer 4h → publier. > 48h = mort. Vitesse = tout', 'tiktok_comments', 'best_practice', 0.82, 'infinite', 'system')
